import UIKit

// MARK: - Route Definition & Validation

enum AppRoute {
    case profile(userID: String)
    case paymentConfirm
    case adminSettings
    case notFound
}

// MARK: - Authorization Service Protocol

protocol AuthorizationServiceProtocol {
    func isAuthenticated() -> Bool
    func isAdmin() -> Bool
    func canAccessPaymentFlows() -> Bool
}

// MARK: - Concrete Authorization Service

final class AuthorizationService: AuthorizationServiceProtocol {
    static let shared = AuthorizationService()
    
    private var currentUserRole: UserRole = .guest
    private var authenticated: Bool = false
    
    enum UserRole {
        case guest
        case user
        case admin
    }
    
    func setAuthState(authenticated: Bool, role: UserRole) {
        self.authenticated = authenticated
        self.currentUserRole = role
    }
    
    func isAuthenticated() -> Bool {
        return authenticated
    }
    
    func isAdmin() -> Bool {
        return authenticated && currentUserRole == .admin
    }
    
    func canAccessPaymentFlows() -> Bool {
        return authenticated && (currentUserRole == .user || currentUserRole == .admin)
    }
}

// MARK: - Universal Link Validator

final class UniversalLinkValidator {
    
    // SECURITY: Strict allowlist of valid hosts
    private static let allowedHosts: Set<String> = [
        "myapp.com",
        "www.myapp.com"
    ]
    
    // SECURITY: Strict allowlist of valid path patterns
    // Each pattern is a regex that matches exactly the allowed routes
    private static let allowedPathPatterns: [(pattern: String, routeBuilder: ([String]) -> AppRoute)] = [
        (
            pattern: "^/profile/([a-zA-Z0-9]{1,64})$",
            routeBuilder: { matches in .profile(userID: matches[0]) }
        ),
        (
            pattern: "^/payment/confirm$",
            routeBuilder: { _ in .paymentConfirm }
        ),
        (
            pattern: "^/admin/settings$",
            routeBuilder: { _ in .adminSettings }
        )
    ]
    
    /// Validates the URL against the allowlist and returns a parsed route.
    /// Returns nil if the URL is not valid or not on the allowlist.
    static func validate(url: URL) -> AppRoute? {
        // SECURITY: Enforce HTTPS only
        guard url.scheme == "https" else {
            logSecurityEvent("Rejected non-HTTPS URL: \(url.absoluteString)")
            return nil
        }
        
        // SECURITY: Validate host against allowlist
        guard let host = url.host?.lowercased(), allowedHosts.contains(host) else {
            logSecurityEvent("Rejected URL with disallowed host: \(url.host ?? "nil")")
            return nil
        }
        
        // SECURITY: Normalize the path to prevent path traversal
        let normalizedPath = normalizePath(url.path)
        
        // SECURITY: Check for path traversal attempts
        guard !normalizedPath.contains("..") && !normalizedPath.contains("//") else {
            logSecurityEvent("Rejected URL with suspicious path: \(normalizedPath)")
            return nil
        }
        
        // SECURITY: Match against allowlisted path patterns only
        for allowedRoute in allowedPathPatterns {
            if let matches = matchPattern(allowedRoute.pattern, in: normalizedPath) {
                let route = allowedRoute.routeBuilder(matches)
                return route
            }
        }
        
        logSecurityEvent("Rejected URL with unrecognized path: \(normalizedPath)")
        return nil
    }
    
    /// Normalizes a URL path by removing trailing slashes and lowercasing
    private static func normalizePath(_ path: String) -> String {
        var normalized = path
        
        // Remove trailing slash (but keep leading slash)
        while normalized.count > 1 && normalized.hasSuffix("/") {
            normalized = String(normalized.dropLast())
        }
        
        // Percent-decode the path to catch encoded traversal attempts
        if let decoded = normalized.removingPercentEncoding {
            normalized = decoded
        }
        
        return normalized
    }
    
    /// Matches a regex pattern against a string and returns captured groups
    private static func matchPattern(_ pattern: String, in string: String) -> [String]? {
        guard let regex = try? NSRegularExpression(pattern: pattern, options: []) else {
            return nil
        }
        
        let range = NSRange(string.startIndex..<string.endIndex, in: string)
        guard let match = regex.firstMatch(in: string, options: [], range: range) else {
            return nil
        }
        
        var captures: [String] = []
        for i in 1..<match.numberOfRanges {
            let captureRange = match.range(at: i)
            if captureRange.location != NSNotFound,
               let swiftRange = Range(captureRange, in: string) {
                captures.append(String(string[swiftRange]))
            }
        }
        
        return captures
    }
    
    private static func logSecurityEvent(_ message: String) {
        // In production, send to your security logging/monitoring service
        print("[SECURITY] \(message)")
    }
}

// MARK: - Parameter Sanitizer

final class ParameterSanitizer {
    
    /// Validates and sanitizes a user ID parameter.
    /// Returns nil if the ID is invalid.
    static func sanitizeUserID(_ rawID: String) -> String? {
        // SECURITY: Validate ID format - alphanumeric only, reasonable length
        let allowedCharacters = CharacterSet.alphanumerics
        guard rawID.unicodeScalars.allSatisfy({ allowedCharacters.contains($0) }) else {
            print("[SECURITY] Rejected user ID with invalid characters: \(rawID)")
            return nil
        }
        
        guard rawID.count >= 1 && rawID.count <= 64 else {
            print("[SECURITY] Rejected user ID with invalid length: \(rawID.count)")
            return nil
        }
        
        return rawID
    }
    
    /// Validates query parameters from a URL, returning only allowed keys with sanitized values.
    static func sanitizeQueryParameters(from url: URL, allowedKeys: Set<String>) -> [String: String] {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems else {
            return [:]
        }
        
        var sanitized: [String: String] = [:]
        for item in queryItems {
            // SECURITY: Only process allowlisted query parameter keys
            guard allowedKeys.contains(item.name) else {
                print("[SECURITY] Ignored disallowed query parameter: \(item.name)")
                continue
            }
            
            if let value = item.value {
                // SECURITY: Basic sanitization - remove control characters
                let cleaned = value.unicodeScalars
                    .filter { !CharacterSet.controlCharacters.contains($0) }
                    .map { String($0) }
                    .joined()
                
                // SECURITY: Enforce reasonable value length
                guard cleaned.count <= 256 else {
                    print("[SECURITY] Rejected query parameter value exceeding max length: \(item.name)")
                    continue
                }
                
                sanitized[item.name] = cleaned
            }
        }
        
        return sanitized
    }
}

// MARK: - Navigation Router

final class NavigationRouter {
    
    private let authService: AuthorizationServiceProtocol
    private weak var navigationController: UINavigationController?
    
    init(navigationController: UINavigationController, authService: AuthorizationServiceProtocol) {
        self.navigationController = navigationController
        self.authService = authService
    }
    
    /// Attempts to navigate to the given route after performing authorization checks.
    /// Returns true if navigation was successful, false if denied.
    @discardableResult
    func navigate(to route: AppRoute) -> Bool {
        switch route {
        case .profile(let userID):
            return navigateToProfile(userID: userID)
            
        case .paymentConfirm:
            return navigateToPaymentConfirm()
            
        case .adminSettings:
            return navigateToAdminSettings()
            
        case .notFound:
            showNotFoundScreen()
            return false
        }
    }
    
    // MARK: - Private Navigation Methods
    
    private func navigateToProfile(userID: String) -> Bool {
        // SECURITY: Validate and sanitize the user ID before use
        guard let sanitizedID = ParameterSanitizer.sanitizeUserID(userID) else {
            print("[SECURITY] Profile navigation blocked: invalid user ID")
            showErrorAlert(message: "Invalid profile link.")
            return false
        }
        
        // SECURITY: Require authentication to view profiles
        guard authService.isAuthenticated() else {
            print("[SECURITY] Profile navigation blocked: user not authenticated")
            showLoginScreen(returnRoute: .profile(userID: sanitizedID))
            return false
        }
        
        let profileVC = ProfileViewController()
        profileVC.userID = sanitizedID
        navigationController?.pushViewController(profileVC, animated: true)
        print("[NAV] Navigated to profile for user: \(sanitizedID)")
        return true
    }
    
    private func navigateToPaymentConfirm() -> Bool {
        // SECURITY: Require authentication AND payment authorization
        guard authService.isAuthenticated() else {
            print("[SECURITY] Payment navigation blocked: user not authenticated")
            showLoginScreen(returnRoute: .paymentConfirm)
            return false
        }
        
        guard authService.canAccessPaymentFlows() else {
            print("[SECURITY] Payment navigation blocked: user not authorized for payment flows")
            showUnauthorizedAlert(message: "You are not authorized to access payment features.")
            return false
        }
        
        let paymentVC = PaymentConfirmViewController()
        // SECURITY: Payment confirmation should re-verify server-side;
        // the deep link only navigates to the screen, it does NOT auto-confirm anything.
        paymentVC.requiresServerSideVerification = true
        navigationController?.pushViewController(paymentVC, animated: true)
        print("[NAV] Navigated to payment confirmation")
        return true
    }
    
    private func navigateToAdminSettings() -> Bool {
        // SECURITY: Require authentication AND admin role
        guard authService.isAuthenticated() else {
            print("[SECURITY] Admin navigation blocked: user not authenticated")
            showLoginScreen(returnRoute: .adminSettings)
            return false
        }
        
        // SECURITY: Strict admin authorization check
        guard authService.isAdmin() else {
            print("[SECURITY] Admin navigation blocked: user is not an admin")
            showUnauthorizedAlert(message: "You do not have admin privileges.")
            return false
        }
        
        let adminVC = AdminSettingsViewController()
        navigationController?.pushViewController(adminVC, animated: true)
        print("[NAV] Navigated to admin settings")
        return true
    }
    
    private func showLoginScreen(returnRoute: AppRoute) {
        let loginVC = LoginViewController()
        loginVC.onLoginSuccess = { [weak self] in
            // After successful login, retry the original navigation
            self?.navigate(to: returnRoute)
        }
        navigationController?.present(loginVC, animated: true)
    }
    
    private func showNotFoundScreen() {
        let notFoundVC = NotFoundViewController()
        navigationController?.pushViewController(notFoundVC, animated: true)
    }
    
    private func showErrorAlert(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        navigationController?.present(alert, animated: true)
    }
    
    private func showUnauthorizedAlert(message: String) {
        let alert = UIAlertController(title: "Access Denied", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        navigationController?.present(alert, animated: true)
    }
}

// MARK: - Universal Link Handler

final class UniversalLinkHandler {
    
    private let router: NavigationRouter
    
    // SECURITY: Rate limiting to prevent abuse via rapid link opening
    private var lastHandledTime: Date = .distantPast
    private let minimumInterval: TimeInterval = 0.5 // 500ms between link handling
    
    init(router: NavigationRouter) {
        self.router = router
    }
    
    /// Main entry point for handling universal links.
    /// Call this from SceneDelegate or AppDelegate.
    @discardableResult
    func handleUniversalLink(_ url: URL) -> Bool {
        // SECURITY: Rate limiting
        let now = Date()
        guard now.timeIntervalSince(lastHandledTime) >= minimumInterval else {
            print("[SECURITY] Rate limited: universal link handled too quickly")
            return false
        }
        lastHandledTime = now
        
        // SECURITY: Validate URL against allowlist and parse route
        guard let route = UniversalLinkValidator.validate(url: url) else {
            print("[SECURITY] Universal link rejected by validator: \(url.absoluteString)")
            return false
        }
        
        // Navigate with authorization checks
        return router.navigate(to: route)
    }
}

// MARK: - App Delegate Integration

class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    var universalLinkHandler: UniversalLinkHandler?
    
    func application(_ application: UIApplication,
                     didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        
        let navigationController = UINavigationController(rootViewController: HomeViewController())
        
        let authService = AuthorizationService.shared
        let router = NavigationRouter(navigationController: navigationController, authService: authService)
        universalLinkHandler = UniversalLinkHandler(router: router)
        
        window = UIWindow(frame: UIScreen.main.bounds)
        window?.rootViewController = navigationController
        window?.makeKeyAndVisible()
        
        return true
    }
    
    // MARK: - Universal Link Handling (iOS 13+ with SceneDelegate, or pre-iOS 13)
    
    func application(_ application: UIApplication,
                     continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        
        // SECURITY: Only handle web browsing activities
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        return universalLinkHandler?.handleUniversalLink(url) ?? false
    }
}

// MARK: - Scene Delegate Integration (iOS 13+)

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    var universalLinkHandler: UniversalLinkHandler?
    
    func scene(_ scene: UIScene,
               willConnectTo session: UISceneSession,
               options connectionOptions: UIScene.ConnectionOptions) {
        
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let navigationController = UINavigationController(rootViewController: HomeViewController())
        
        let authService = AuthorizationService.shared
        let router = NavigationRouter(navigationController: navigationController, authService: authService)
        universalLinkHandler = UniversalLinkHandler(router: router)
        
        window = UIWindow(windowScene: windowScene)
        window?.rootViewController = navigationController
        window?.makeKeyAndVisible()
        
        // Handle universal links that launched the scene
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            universalLinkHandler?.handleUniversalLink(url)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        
        universalLinkHandler?.handleUniversalLink(url)
    }
}

